+
+  const coordinator = new FederatedLearningCoordinator({
+    agentId: 'coordinator',
+    minQuality: 0.7,
+    maxAgents: 50 // Limit to 50 most recent agents
+  });
+
+  console.log('Simulating 100 distributed agents...');
+
+  // Simulate 100 agents reporting
+  for (let i = 0; i < 100; i++) {
